import{c as a,bn as e,aU as r,aX as d,x as l,a2 as h}from"./chunks/framework.EkwLm6yr.js";const m=JSON.parse('{"title":"那刹","description":"","frontmatter":{"order":4},"headers":[],"relativePath":"地图/幽冥血海/那刹.md","filePath":"地图/幽冥血海/那刹.md","lastUpdated":0}'),n={name:"地图/幽冥血海/那刹.md"};function i(s,t,b,o,c,x){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="那刹" tabindex="-1">那刹 <a class="header-anchor" href="#那刹" aria-label="Permalink to “那刹”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">鬼影叶</td><td style="text-align:center;">琥珀露</td><td style="text-align:center;">青冥绡</td></tr></tbody></table><h2 id="抱犊山" tabindex="-1">抱犊山 <a class="header-anchor" href="#抱犊山" aria-label="Permalink to “抱犊山”">​</a></h2><h3 id="拘魂鬼王" tabindex="-1">拘魂鬼王 <a class="header-anchor" href="#拘魂鬼王" aria-label="Permalink to “拘魂鬼王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：技能命中敌人时会在场景中随机位置召唤出一个鬼魂</td></tr><tr><td>普通攻击：朝前连续爪击，随后原地旋转打击敌人</td></tr><tr><td>影遁瞬袭：消失片刻后出现在敌人身后，使出撕裂一击</td></tr><tr><td>疾影坠击：分散自己的一屡魂魄，魂魄出现在目标头顶下砸，本体则朝前水平冲刺。两者先后顺序随机</td></tr><tr><td>剥魂鬼爪：从虚空中伸出幽影爪朝前方抓取，将敌人灵魂抽离出来，灵魂受到的伤害将等额传递至本体上，若灵魂被击碎还会对其本体造成晕眩和长时间混乱。鬼王会优先攻击魂魄</td></tr><tr><td>魅影鬼爪：鬼爪在敌人四个方向出现，其中3只化为虚影逐渐消失，只有1只鬼爪命中后给敌人添加缠怨效果<br>缠怨：抑制目标回血，持续扣血并附带高额减速效果</td></tr><tr><td>幽魄归元：全身无实体化，吸收场上全部鬼魂，每个鬼魂会为鬼王回复一定的生命值，并提供短暂的攻击力加成</td></tr><tr><td>引魂怨歌：高声吟唱，2秒内鬼王每次受到攻击都会在场景随机位置召唤1个鬼魂</td></tr></tbody></table><p>掉落道具：那刹防具制作书</p><h2 id="彼岸花海" tabindex="-1">彼岸花海 <a class="header-anchor" href="#彼岸花海" aria-label="Permalink to “彼岸花海”">​</a></h2><h3 id="花妖曼珠" tabindex="-1">花妖曼珠 <a class="header-anchor" href="#花妖曼珠" aria-label="Permalink to “花妖曼珠”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普攻：抬起法杖，在目标脚底生成一朵彼岸花，一段时间后向上生成花粉能量造成伤害</td></tr><tr><td>绮梦碎影：朝前方生成多朵彼岸花，一小段时间后一起爆炸，对碰到的敌人造成伤害（部分伤害无法被护盾抵挡）</td></tr><tr><td>飞花追影：花妖凝聚彼岸花瓣之力，发射出飞花追踪目标</td></tr><tr><td>迷幻花粉：boss在左侧或右侧区域制造一片大范围迷幻花粉，存在一段时间（处于迷幻花粉中，角色的移速、攻击和命中下降，并持续扣血，长时间处于花粉中将被晕眩）</td></tr><tr><td>彼岸之泪：花妖吸取场景花海中鬼火和幽灵能量，凝聚出一滴晶莹剔透的彼岸之泪，而后脚底盛开出一朵巨大彼岸花，朝四周释放能量造成伤害（部分伤害无法被护盾抵挡）</td></tr><tr><td>花海再生：花妖吸取花海能量，围绕自身周围生成一层花瓣护盾（霸体并免疫负面），自身缓慢回复生命（若受到角色的技能攻击，boss会加速回复生命值）</td></tr></tbody></table><p>掉落道具：那刹武器制作书（第一心法）</p><h2 id="彼岸花海隐藏" tabindex="-1">彼岸花海隐藏 <a class="header-anchor" href="#彼岸花海隐藏" aria-label="Permalink to “彼岸花海隐藏”">​</a></h2><p>使用普通攻击，将地图上方的<strong>所有冤魂</strong>击落，开启<strong>隐藏入口</strong></p><img src="'+l+'" alt="彼岸花海隐藏" style="zoom:50%;"><h3 id="叶妖沙华" tabindex="-1">叶妖沙华 <a class="header-anchor" href="#叶妖沙华" aria-label="Permalink to “叶妖沙华”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普攻：叶妖挥舞双手的叶片，对周围的敌人造成伤害</td></tr><tr><td>万叶归斩：叶妖双手持叶片，朝前方急行留下横向叶刃痕迹，而后跃起下劈落下，留下纵向叶刃痕迹。短暂延迟后叶刃痕迹炸开消失，造成真实伤害（无法被护盾抵挡）</td></tr><tr><td>叶影囚笼：叶妖操控周围的叶子，在自身周围生成一个由绿叶构成的巨大囚笼（囚笼刚形成时，将碰到的玩家吸入囚笼中央，普攻攻击2次可打破囚笼）</td></tr><tr><td>叶影分身：叶妖分化出为2个分身，而后本体随机与其中一个分身互换位置（分身不会移动，会跟随boss释放普攻和叶刃风暴）</td></tr><tr><td>叶刃风暴：叶妖旋转身体，周围的叶子随之形成旋风，对敌人进行持续的切割攻击</td></tr><tr><td>彼岸叶株：在地面召唤2个彼岸叶株，存在一段时间<br>2个彼岸叶株时叶妖无敌<br>1个彼岸叶株时叶妖获得霸体、减伤、免疫负面效果，而角色的暴击下降</td></tr></tbody></table><p>掉落道具：那刹武器制作书（第二心法）</p><h2 id="往生路" tabindex="-1">往生路 <a class="header-anchor" href="#往生路" aria-label="Permalink to “往生路”">​</a></h2><h3 id="鬼帝嵇康" tabindex="-1">鬼帝嵇康 <a class="header-anchor" href="#鬼帝嵇康" aria-label="Permalink to “鬼帝嵇康”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普通攻击：嵇康奏响夺舍琴乐，朝敌人发出两道摄魂音波</td></tr><tr><td>乱弦横波：嵇康拨动琴弦，在玩家两侧生成两个音源，朝内释放音波干扰，混乱命中的敌人</td></tr><tr><td>弹跳音律：嵇康弹拨琴弦，向外发射1个弹跳音波</td></tr><tr><td>音流激射：嵇康快速拨弄几下琴弦，连续朝固定方向发射出几个不同的音符</td></tr><tr><td>阴魂狂曲：嵇康奏响让人癫狂的阴魂乐曲，略微降低防御力但是提高双帝的攻击力和暴击率</td></tr><tr><td>镇魂音域：嵇康疯狂挑拨琴弦，在场景内连续创造多个圆形波谱，布满左半屏，伤害极高</td></tr><tr><td>场景互动：生域和亡域之间存在无法跨越的鸿沟，仅通过左右两侧的传送门连通。单侧传送门每隔5秒开启</td></tr></tbody></table><h3 id="鬼帝周乞" tabindex="-1">鬼帝周乞 <a class="header-anchor" href="#鬼帝周乞" aria-label="Permalink to “鬼帝周乞”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普通攻击：周乞手上的夺舍剑消失，随后从敌人附近的虚空出现，从下往上挑，随后在空中对目标戳刺</td></tr><tr><td>裁决鬼剑：在敌人头顶出现一把审判之剑，根据敌人与剑的位置关系决定审判剑接下来发动的技能<br>贪婪：追击敌人挥砍出三连击，每一段挥砍都朝向目标并附带位移<br>傲慢：分出剑幻影，从空中以不同角度落下<br>无知：大范围横扫，同时甩出3团魂火</td></tr><tr><td>刺血飞剑：朝空中抛出剑，瞄准敌人的方向，随后沿该方向飞行突刺，突刺结束后停留在原地旋转，继续瞄准敌人的方向，对命中的敌人造成失血效果，使其无法回复血量</td></tr><tr><td>吸星摄魂：偷取敌人部分属性收纳于剑中，通过对周乞造成一定伤害后归还属性</td></tr><tr><td>万剑归宗：左侧天空下起剑雨，无数把利剑从天落下，覆盖右半边全部屏幕，伤害极高</td></tr><tr><td>场景互动：生域和亡域之间存在无法跨越的鸿沟，仅通过左右两侧的传送门连通。单侧传送门每隔5秒开启</td></tr></tbody></table><p>掉落道具：那刹三生坠制作书</p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="那刹摄魂琴" tabindex="-1">那刹摄魂琴 <a class="header-anchor" href="#那刹摄魂琴" aria-label="Permalink to “那刹摄魂琴”">​</a></h3><img src="'+h+'" alt="那刹摄魂琴" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">19~26</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">11~15</td></tr><tr><td style="text-align:center;">吸血</td><td style="text-align:center;">15~20</td></tr><tr><td style="text-align:center;">反伤</td><td style="text-align:center;">15~20</td></tr></tbody></table>',27)])])}const _=a(n,[["render",i]]);export{m as __pageData,_ as default};
